11		"forge-cli/pkg/e2eprobe"
12		"forge-cli/pkg/feature"
13		"forge-cli/pkg/just"
14		"forge-cli/pkg/project"
15		"forge-cli/pkg/task"
16		tmpl "forge-cli/pkg/template"
17		"forge-cli/pkg/testrunner"
18	
19		"github.com/spf13/cobra"
20	)
21	
22	var qualityGateVerbose bool
23	
24	// maxFixTasksPerStep caps the number of active fix-tasks per quality-gate step.
25	// When this limit is reached, no new fix-tasks are created for that step.
26	const maxFixTasksPerStep = 3
27	
28	// ErrMaxFixTasks is returned when the maximum number of active fix-tasks for a
29	// quality-gate step has been reached.
30	var ErrMaxFixTasks = errors.New("max fix-tasks reached")
31	
32	var qualityGateCmd = &cobra.Command{
33		Use:   "quality-gate",
34		Short: "Check if all tasks are done, then run tests",
35		Long: `Checks if every task in the current feature is completed or skipped.
36			Exits 0 silently if any task is still pending, in_progress, or blocked (no-op).
37			If all done: runs project-wide unit/integration tests, then e2e regression.
38	
39			Feature e2e tests are run by T-test-3 (run-e2e-tests task), not this hook.
40			This hook is the project health gate: unit tests + regression suite.
41	
42			Use -v to see why the command exits early (useful for debugging).`,
43		Run: runQualityGate,
44	}
45	
46	func init() {
47		qualityGateCmd.Flags().BoolVarP(&qualityGateVerbose, "verbose", "v", false, "print debug info when exiting early")
48	}
49	
50	// AllCompletedResult holds context for running tests after all tasks complete.
51	type AllCompletedResult struct {
52		FeatureSlug string
53		ProjectRoot string
54		TestCommand string // empty if not set in index.json
55	}
56	
57	// checkAllCompleted verifies all tasks are done and returns test context.
58	// Returns nil when tasks are not all done — caller should exit silently.
59	func checkAllCompleted(verbose bool) *AllCompletedResult {
60		projectRoot, err := project.FindProjectRoot()
61		if err != nil {
62			Debugf(verbose, "project root not found: %v", err)
63			return nil
64		}
65		Debugf(verbose, "project root: %s", projectRoot)
66	
67		featureSlug, err := feature.GetCurrentFeature(projectRoot)
68		if err != nil {
69			Debugf(verbose, "feature not found: %v", err)
70			return nil
71		}
72		Debugf(verbose, "feature: %s", featureSlug)
73	
74		// Guard: only proceed if .forge/state.json signals allCompleted.
75		forgeState := feature.ReadForgeState(projectRoot)
76		if forgeState == nil || !forgeState.AllCompleted {
77			Debugf(verbose, "no forge state with allCompleted — skipping")
78			return nil
79		}
80		Debugf(verbose, "forge state: feature=%s allCompleted=true", forgeState.Feature)
81	
82		// Consume the state — clear it before proceeding
83		_ = feature.ClearForgeState(projectRoot)
84	
85		indexPath := filepath.Join(projectRoot, feature.GetFeatureIndexFile(featureSlug))
86		index, err := task.LoadIndex(indexPath)
87		if err != nil {
88			Debugf(verbose, "index.json not found: %s (%v)", indexPath, err)
89			return nil
90		}
91		Debugf(verbose, "loaded index: %d tasks", index.TaskCount())
92	
93		// All tasks must be completed or skipped (rejected does not count as done)
94		for _, t := range index.TasksMap() {
95			if t.Status != feature.StatusCompleted && t.Status != feature.StatusSkipped {
96				Debugf(verbose, "task %s is %s — not all done", t.ID, t.Status)
97				return nil
98			}
99		}
100	
101		return &AllCompletedResult{
102			FeatureSlug: featureSlug,
103			ProjectRoot: projectRoot,
104			TestCommand: index.TestCommand,
105		}
106	}
107	
108	func runQualityGate(_ *cobra.Command, _ []string) {
109		result := checkAllCompleted(qualityGateVerbose)
110		if result == nil {
111			os.Exit(0) // not all done is normal, exit silently
112		}
113	
114		fmt.Fprintf(os.Stderr, "=== All tasks completed for feature: %s ===\n", result.FeatureSlug)
115	
116		// Warn if feature e2e scripts exist but haven't been graduated.
117		e2eScriptsDir := feature.GetE2EStagingDir(result.ProjectRoot, result.FeatureSlug)
118		markerPath := feature.GetE2EGraduatedMarker(result.ProjectRoot, result.FeatureSlug)
119		if just.FileExists(e2eScriptsDir) && !just.FileExists(markerPath) {
120			fmt.Fprintln(os.Stderr,
121				"WARNING: feature e2e scripts exist but haven't been run or graduated.\n"+
122					"  Add T-test-3 (run-e2e-tests) and T-test-4 (graduate-tests) to your task index,\n"+
123					"  or run /run-e2e-tests and /graduate-tests manually.")
124		}
125	
126		// Step 1: Quality gate (compile -> fmt -> lint)
127		// Stops at first blocking failure.
128		gateSteps := just.LintGateSequence()
129		just.RunGate(result.ProjectRoot, "", gateSteps, func(step, output string) {
130			fmt.Fprintf(os.Stderr, "ERROR: %s check failed\n", step)
131			errorDocPath := "tests/results/unit-raw-output.txt"
132			if output != "" {
133				if err := writeUnitTestRawOutput(result.ProjectRoot, "=== "+step+" failure ===\n"+output); err != nil {
134					fmt.Fprintf(os.Stderr, "WARNING: failed to write %s output: %v\n", step, err)
135				}
136			}
137			fixID, _ := addFixTask(result.ProjectRoot, result.FeatureSlug, step, output, errorDocPath)
138			handleGateFailure(step, errorDocPath, fixID, just.ExtractConciseError(output, 5))
139		})
140	
141		// Step 2: Project-wide unit/integration tests
142		fmt.Fprintln(os.Stderr, "--- Running project-wide tests ---")
143		unitOutput, unitSuccess := testrunner.RunProjectTests(result.ProjectRoot, result.TestCommand)
144		if !unitSuccess {
145			fmt.Fprintln(os.Stderr, "ERROR: unit tests failed")
146			errorDocPath := "tests/results/unit-raw-output.txt"
147			if unitOutput != "" {
148				if err := writeUnitTestRawOutput(result.ProjectRoot, unitOutput); err != nil {
149					fmt.Fprintf(os.Stderr, "WARNING: failed to write unit test output: %v\n", err)
150				}
151			}
152			fixID, _ := addFixTask(result.ProjectRoot, result.FeatureSlug, "unit-test", unitOutput, errorDocPath)
153			handleGateFailure("unit-test", errorDocPath, fixID, just.ExtractConciseError(unitOutput, 5))
154		}
155	
156		// Step 3: Full e2e regression (graduated scripts in tests/e2e/)
157		if just.HasJustfile(result.ProjectRoot) && just.HasRecipe(result.ProjectRoot, "test-e2e") {
158			e2eReady := true
159			if just.HasRecipe(result.ProjectRoot, "e2e-setup") {
160				fmt.Fprintln(os.Stderr, "--- Ensuring e2e dependencies (just e2e-setup) ---")
161				setupOutput, setupSuccess := just.RunCapture(result.ProjectRoot, "just", "e2e-setup")
162				if !setupSuccess {
163					fmt.Fprintln(os.Stderr, "WARNING: e2e-setup failed; skipping e2e regression")
164					fmt.Fprintln(os.Stderr, "  To retry manually: just e2e-setup && just test-e2e")
165					if setupOutput != "" {
166						if err := writeRegressionRawOutput(result.ProjectRoot, "=== e2e-setup failure ===\n"+setupOutput); err != nil {
167							fmt.Fprintf(os.Stderr, "WARNING: failed to write setup output: %v\n", err)
168						} else {
169							fmt.Fprintln(os.Stderr, "  Setup output saved to tests/e2e/results/raw-output.txt")
170						}
171					}
172					e2eReady = false
173				}
174			}
175			if e2eReady {
176				if !e2eprobe.ProbeServers(result.ProjectRoot, "") {
177					fmt.Fprintln(os.Stderr, "WARNING: e2e server health check failed; skipping e2e regression")
178					fmt.Fprintln(os.Stderr, "  Start dev server and retry: just dev && just test-e2e")
179					e2eReady = false
180				}
181			}
182			if e2eReady {
183				fmt.Fprintln(os.Stderr, "--- Running full e2e regression (just test-e2e) ---")
184				regressionOutput, regSuccess := just.RunCapture(result.ProjectRoot, "just", "test-e2e")
185				if !regSuccess {
186					fmt.Fprintln(os.Stderr, "ERROR: e2e regression failed")
187					errorDocPath := "tests/e2e/results/raw-output.txt"
188					if regressionOutput != "" {
189						if err := writeRegressionRawOutput(result.ProjectRoot, regressionOutput); err != nil {
190							fmt.Fprintf(os.Stderr, "WARNING: failed to write raw-output.txt: %v\n", err)
191						}
192					}
193					fixID, _ := addFixTask(result.ProjectRoot, result.FeatureSlug, "test-e2e", regressionOutput, errorDocPath)
194					handleGateFailure("test-e2e", errorDocPath, fixID, just.ExtractConciseError(regressionOutput, 5))
195				}
196			}
197		}
198	}
199	
200	// handleGateFailure prints the hook JSON block reason and exits.
201	// fixID is the ID returned by addFixTask; empty means task creation failed.
202	func handleGateFailure(step, errorDocPath, fixID, concise string) {
203		action := "run `task add --template fix-task` to create one manually, then `task claim`"
204		if fixID != "" {
205			action = "run `task claim` to pick it up"
206		}
207	
208		guide := map[string]string{
209			"compile":   "fix compilation errors",
210			"lint":      "fix lint errors",
211			"unit-test": "fix failing tests",
212			"test-e2e":  "fix failing e2e tests",
213		}
214		label := map[string]string{
215			"compile":   "Project compilation",
216			"lint":      "Lint check",
217			"unit-test": "Unit tests",
218			"test-e2e":  "E2e regression tests",
219		}
220	
221		g := guide[step]
222		if g == "" {
223			g = "fix the issue"
224		}
225		l := label[step]
226		if l == "" {
227			l = testrunner.Capitalize(step) + " check"
228		}
229	
230		var fixMsg string
231		if fixID != "" {
232			fixMsg = fmt.Sprintf("Fix task %s added (P0, breaking)", fixID)
233		} else {
234			fixMsg = "Failed to add fix task automatically"
235		}
236	
237		reason := fmt.Sprintf(
238			"%s failed in quality-gate hook. %s — %s and %s.\nError output: %s\n%s",
239			l, fixMsg, action, g, errorDocPath, concise)
240	
241		testrunner.PrintHookJSON(map[string]any{
242			"decision": "block",
243			"reason":   reason,
244		})
245		os.Exit(0)
246	}
247	
248	// sourceFileRe matches source file paths followed by :line or :line:col patterns.
249	var sourceFileRe = regexp.MustCompile(`([\w][\w./-]*\.\w{1,10})(?::\d+){1,2}`)
250	
251	// sourceExts is a whitelist of source code extensions for file extraction.
252	var sourceExts = map[string]bool{
253		".go": true, ".ts": true, ".js": true, ".tsx": true, ".jsx": true,
254		".py": true, ".rs": true, ".java": true, ".rb": true,
255		".c": true, ".cpp": true, ".h": true, ".hpp": true,
256		".css": true, ".scss": true, ".html": true, ".sql": true,
257		".vue": true, ".svelte": true,
258	}
259	
260	// extractSourceFiles parses error output and returns comma-separated file paths.
261	func extractSourceFiles(output string) string {
262		seen := make(map[string]bool)
263		var files []string
264		for _, match := range sourceFileRe.FindAllStringSubmatch(output, -1) {
265			path := strings.TrimPrefix(match[1], "./")
266			if path == "" || seen[path] {
267				continue
268			}
269			if !sourceExts[filepath.Ext(path)] {
270				continue
271			}
272			seen[path] = true
273			files = append(files, path)
274		}
275	
276		if len(files) > 10 {
277			files = files[:10]
278		}
279		if len(files) == 0 {
280			return "See error output for affected files"
281		}
282		return strings.Join(files, ", ")
283	}
284	
285	// countActiveFixTasks counts fix-tasks for a step that are not in a terminal state
286	// (completed or skipped). A fix-task is identified by having a non-empty SourceTaskID
287	// AND a title with the prefix "fix <step>:".
288	func countActiveFixTasks(index *task.TaskIndex, step string) int {
289		count := 0
290		prefix := "fix " + step + ":"
291		for _, t := range index.TasksMap() {
292			if t.SourceTaskID != "" &&
293				strings.HasPrefix(t.Title, prefix) &&
294				t.Status != "completed" &&
295				t.Status != "skipped" {
296				count++
297			}
298		}
299		return count
300	}
301	
302	// addFixTask creates a fix task using the same internal API as `task add`.
303	// Mirrors executeAdd() from add.go: template defaults -> AddTask -> CreateTaskMarkdown -> EnsureForgeState.
304	// Returns (taskID, nil) on success, ("", ErrMaxFixTasks) when the fix-task cap is exceeded.
305	func addFixTask(projectRoot, featureSlug, step, output, errorDocPath string) (string, error) {
306		indexPath := filepath.Join(projectRoot, feature.GetFeatureIndexFile(featureSlug))
307	
308		// Check cap before creating a new fix-task.
309		index, err := task.LoadIndex(indexPath)
310		if err != nil {
311			fmt.Fprintf(os.Stderr, "WARNING: failed to load index for cap check: %v\n", err)
312			// Proceed without cap check if index can't be loaded.
313		} else {
314			active := countActiveFixTasks(index, step)
315			if active >= maxFixTasksPerStep {
316				fmt.Fprintf(os.Stderr, "max fix-tasks reached for %s, manual intervention required\n", step)
317				return "", ErrMaxFixTasks
318			}
319		}
320	
321		sourceFiles := extractSourceFiles(output)
322	
323		testScript := "just " + step
324		if step == "unit-test" {
325			testScript = "just test"
326		}
327	
328		title := fmt.Sprintf("fix %s: %s failure in quality gate", step, testScript)
329		description := fmt.Sprintf(
330			"Quality gate step `%s` failed during quality-gate hook.\n\n"+
331				"Error output saved to: `%s`\n\n"+
332				"Concise error:\n```\n%s\n```",
333			testScript, errorDocPath, just.ExtractConciseError(output, 10),
334		)
335	
336		// Build opts — Priority/Breaking/EstimatedTime intentionally hardcoded
337		// (not read from template defaults) since this is a programmatic caller.
338		opts := task.AddTaskOpts{
339			Title:         title,
340			Priority:      "P0",
341			EstimatedTime: "30min",
342			Breaking:      true,
343			Description:   description,
344			Template:      "fix-task",
345			Vars: map[string]string{
346				"SOURCE_FILES":   sourceFiles,
347				"TEST_SCRIPT":    testScript,
348				"TEST_RESULTS":   errorDocPath,
349				"SOURCE_TASK_ID": "N/A (project-wide gate)",
350			},
351		}
352	
353		tasksDir := filepath.Join(projectRoot, feature.GetFeatureTasksDir(featureSlug))
354	
355		if _, err := tmpl.Get(opts.Template); err != nil {
356			fmt.Fprintf(os.Stderr, "WARNING: template %q not found: %v\n", opts.Template, err)
357			return "", nil
358		}
359		if defs, err := tmpl.GetDefaults(opts.Template); err == nil && defs.IDPrefix != "" {
360			opts.IDPrefix = defs.IDPrefix
361		}
362	
363		id, err := task.AddTask(indexPath, opts)
364		if err != nil {
365			fmt.Fprintf(os.Stderr, "WARNING: failed to add fix task: %v\n", err)
366			return "", nil
367		}
368	
369		opts.ID = id
370	
371		if err := task.CreateTaskMarkdown(tasksDir, id+".md", opts); err != nil {
372			fmt.Fprintf(os.Stderr, "WARNING: failed to create fix task file: %v\n", err)
373			return "", nil
374		}
375	
376		if err := feature.EnsureForgeState(projectRoot, featureSlug); err != nil {
377			fmt.Fprintf(os.Stderr, "WARNING: failed to update .forge/state.json: %v\n", err)
378		}
379	
380		fmt.Fprintf(os.Stderr, "Fix task %s added (P0, breaking)\n", id)
381		return id, nil
382	}
383

